package main.rice.node;

import main.rice.obj.APyObj;
import java.util.List;
import java.util.Set;

/**
 * An abstract class representing a node that can generate Python objects.
 * Each node can generate exhaustive values (all possible values in a domain)
 * or random values (random samples from a domain).
 *
 * @param <ValueType> the type of Python object this node generates
 */
public abstract class APyNode<ValueType extends APyObj> {

    /**
     * The exhaustive domain - a list of integers representing configuration
     * for exhaustive value generation (e.g., list lengths to generate).
     */
    protected List<Integer> exDomain;

    /**
     * The random domain - a list of integers representing configuration
     * for random value generation (e.g., list lengths to generate randomly).
     */
    protected List<Integer> ranDomain;

    /**
     * Gets the exhaustive domain for this node.
     *
     * @return the exhaustive domain for this node
     */
    public List<Integer> getExDomain() {
        return this.exDomain;
    }

    /**
     * Sets the exhaustive domain for this node.
     *
     * @param exDomain the exhaustive domain for this node
     */
    public void setExDomain(List<Integer> exDomain) {
        this.exDomain = exDomain;
    }

    /**
     * Gets the random domain for this node.
     *
     * @return the random domain for this node
     */
    public List<Integer> getRanDomain() {
        return this.ranDomain;
    }

    /**
     * Sets the random domain for this node.
     *
     * @param ranDomain the random domain for this node
     */
    public void setRanDomain(List<Integer> ranDomain) {
        this.ranDomain = ranDomain;
    }

    /**
     * Generates all exhaustive values for this node based on the exhaustive domain.
     *
     * @return a set of all exhaustive values
     */
    public abstract Set<ValueType> genExVals();

    /**
     * Generates a single random value for this node based on the random domain.
     *
     * @return a randomly generated value
     */
    public abstract ValueType genRandVal();

    /**
     * Gets the left child node (for nodes with children).
     *
     * @return the left child node, or null if not applicable
     */
    public APyNode<?> getLeftChild() {
        return null;
    }

    /**
     * Gets the right child node (for nodes with two children).
     *
     * @return the right child node, or null if not applicable
     */
    public APyNode<?> getRightChild() {
        return null;
    }
}

